"""
MKT Original Layer — Ecclesiastes chapters 10–12
Run: python3 scripts/zc-original-ecclesiastes-10-12.py

Ch10: Wisdom-folly contrast proverbs; shegagah (unintentional blunder) from rulers;
      social inversions; danger-proverbs; baal-halashon (master of tongue);
      na'ar / ben-chorim (boy-king vs. son of freemen); bird-carries-words (10:20)
Ch11: Bread-on-waters (commercial/generosity); ruach (wind/spirit dual sense, 11:5);
      sow morning and evening; simcha (joy) + judgment
Ch12: Extended dying-body allegory (12:1-7); ro'eh echad (one Shepherd, 12:11);
      sof davar (conclusion of the matter, 12:13); kol ha'adam (the whole of man)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "10": {
    "1": "<p><strong>zevuvei mavet yavbish yabbia shemen roqeach</strong>: 'Dead flies cause the perfumer's ointment to give off a foul smell.' <em>Zevuvei mavet</em> (flies of death) — the construct chain places death inside the plural noun, making them death-flies rather than ordinary flies. <em>Yabbish</em> (cause to stink) and <em>yabbia</em> (cause to ferment/bubble over) — two causative verbs describing what a small contaminant does to the compound. <em>Roqeach</em> (perfumer/ointment-maker) — a specialized craftsman; the ointment represents accumulated skilled work that a trivial impurity destroys. <em>Mikavod hochmah</em> (more than honor [is] wisdom) — the second half uses a comparative min: a little folly outweighs wisdom-and-honor. The syntax forces the reader to hold the equivalence: much accumulated good, a little folly, and the folly wins.</p>",
    "2": "<p><strong>lev chakham li-ymino ulev kesil li-smolo</strong>: 'The heart of the wise goes to the right, but the heart of the fool to the left.' <em>Lev</em> (heart) encompasses the whole inner orientation — not merely emotion but will, understanding, and character. <em>Yamin</em> (right) and <em>smol</em> (left) — in ANE symbolic geography, right = the place of honor, safety, favor (cf. Ps 110:1, God's right hand; Matt 25:33-34, sheep on the right). The proverb maps the interior orientation of the wise onto the culturally coded direction of honor and security, while the fool's heart navigates toward the side associated with dishonor and danger.</p>",
    "3": "<p><strong>gam baderekh keshal libo holekh</strong>: 'Even while walking along the road, the fool's heart fails him.' <em>Sekhel</em> (wisdom, discernment, good sense) — the same root as <em>maskil</em> (one who understands). The fool walking on the road — not in any extraordinary situation but in the ordinary act of travel — demonstrates his lack of judgment (<em>libo holekh</em>, his heart goes; here indicating his character reveals itself in motion). <em>Ve'amar lekhol sakhal hu</em>: 'and he says of everyone that he is a fool' — the fool diagnoses others as foolish rather than examining himself. The projection of folly onto others is itself the demonstration of folly.</p>",
    "4": "<p><strong>al tanach mimqomekha</strong>: 'Do not abandon your post.' <em>Maqom</em> (place, post, station) — the position of responsibility one holds under a superior. <em>Marpe yanieach chatao'im gedolim</em>: 'composure sets aside great offenses.' <em>Marpe</em> (composure, healing, calm) — the same root as <em>marpe lashon</em> (healing tongue) in Prov 12:18. Here it describes not verbal but behavioral composure under the ruler's anger. The wisdom insight: controlled non-reaction (<em>marpe</em>) has the power to defuse situations that reactive self-defense would escalate. The post is to be held because abandonment signals guilt and triggers exactly the pursuit the composed person avoids.</p>",
    "5": "<p><strong>shegagah yotze'et milifnei hashalit</strong>: 'A blunder that proceeds from those in power.' <em>Shegagah</em> (unintentional mistake, inadvertent sin) — in the legal tradition, this is the term for accidental transgression requiring the atonement of Lev 4-5. Qohelet uses it for the category of governing blunder that is not malicious but produces serious harm anyway. <em>Shallit</em> — borrowed from Aramaic; used in Ecclesiastes for supreme authority. The verse observes that major social ills often originate not from deliberate wickedness but from the inadvertent failures of those with power — a shrewd political observation without parallel in the legal codes.</p>",
    "6": "<p><strong>nittan hassekl bimromim rabbim</strong>: 'Fools are appointed to high positions.' <em>Sekhel</em> (folly, stupidity) as a nominalized form — the fool himself elevated to <em>meromim rabbim</em> (the heights, the great heights), while the <em>ashirim</em> (the capable, the wealthy) sit in lowly positions. The social inversion that Qohelet catalogues as <em>ra'ah ra'iti</em> (an evil I have seen) is the misallocation of authority — the wisdom tradition consistently argues that authority should track with character and competence; when it does not, the mismatch is a sign of social corruption rather than a stable new order.</p>",
    "7": "<p><strong>ra'iti avadim al susim</strong>: 'I have seen servants riding on horseback.' Horses in the ancient world were the conveyance of military commanders and kings — not a transportation option for servants. The social reversal: servants (<em>avadim</em>) on horseback, princes (<em>sarim</em>) walking on foot. <em>Kekhavadim</em> (like servants) — the closing comparative locks the inversion: the princes walk in the manner appropriate to servants, having ceded the status-marker of mounted travel to those below them. Qohelet is documenting the breakdown of the social order whose disruption he traced to the governing blunder of verse 5.</p>",
    "8": "<p><strong>kore shachat bah yipol</strong>: 'Whoever digs a pit may fall into it.' The pit-trap proverb appears in Prov 26:27 and Ps 7:15-16 — the trap intended for others becomes the trap of the trapper. <em>Poretz gader yishkenu nachash</em>: 'whoever breaks through a wall will be bitten by a snake.' <em>Poretz gader</em> (break through a hedge/wall) — the violation of a boundary-wall, whether property or covenant. <em>Nachash</em> (serpent/snake) — the snake in the wall is the consequence of boundary-breaking. Both proverbs in this verse are concrete observations about the recoil of aggression: the dug pit and the broken wall both return damage to their maker.</p>",
    "9": "<p><strong>massa avenim ye'atsev bam</strong>: 'Whoever quarries stones may be hurt by them.' The labor-danger proverbs of vv.8-9 do not condemn the work but observe the inherent risk in every occupation. <em>Baqea etzim yissaken bam</em>: 'whoever splits wood is in danger from it.' <em>Yissaken</em> (is endangered/exposed to danger) — from the root connected to being set at risk or exposed. The four danger-proverbs (pit-digging, wall-breaking, stone-quarrying, wood-splitting) are Qohelet's way of observing that every form of activity aimed at altering or extracting from the natural order carries the possibility of reversal — the thing worked upon may work back.</p>",
    "10": "<p><strong>im qehe habarzel velo pannim qilqal</strong>: 'If an axe is dull and you do not sharpen it.' <em>Qilqal</em> (to sharpen, lit. to make light/smooth) — the polishing of the blade's edge. <em>Yegaber chayyalim</em>: 'you will need to use much more strength.' <em>Chayyalim</em> (strengths, forces) — the intensification of labor required by a blunt instrument. <em>Yitron hakshir chokhmah</em>: 'wisdom is the advantage of skill.' <em>Yitron</em> (advantage, profit) — the key Ecclesiastes term for what endures and what gains. Here wisdom is identified with the pre-work sharpening that reduces the overall effort required: skill preparation is the <em>yitron</em> that multiplies effectiveness.</p>",
    "11": "<p><strong>im yishokh hannachash belo lachash</strong>: 'If a snake bites before being charmed.' <em>Lachash</em> (charm, whisper — the whispering incantation of the snake charmer) — the professional practice of charming serpents by sound. <em>Ve'ein yitron lebaal halashon</em>: 'there is no profit for the master of the tongue.' <em>Baal halashon</em> (master of the tongue, lord of the tongue) — the one whose professional skill is verbal, including the snake charmer and, by extension, the advisor or orator who acts too late. If the snake has already bitten, no amount of verbal skill undoes it. Qohelet uses the wordplay: <em>lachash</em> (charm) and <em>lashon</em> (tongue) share consonants — the charmer's tongue that failed to act in time has no <em>yitron</em>.</p>",
    "12": "<p><strong>divrei pi chakham chen</strong>: 'The words of the wise man's mouth are grace/goodwill.' <em>Chen</em> (grace, charm, favor, goodwill) — the social capital that wise speech creates. <em>Uve-siftot kesil tevallenu</em>: 'but the lips of a fool devour him.' <em>Tevallenu</em> (will swallow him, devour him) — the root <em>bala</em> used for swallowing. The wise man's speech creates grace for him; the fool's speech swallows him. The same instrument (the mouth/lips) produces opposite results depending on the character behind it — a concise statement of the tongue-wisdom that runs through the entire wisdom tradition.</p>",
    "13": "<p><strong>techillat divrei pihu siklut</strong>: 'The beginning of his mouth's words is folly.' <em>Siklut</em> (folly, stupidity) — a characteristic Ecclesiastes word for the fullest form of human foolishness. <em>Ve'acharit pihu ra'ah holelut</em>: 'and the end of his mouth is wicked madness.' <em>Holelut</em> (madness, raving) — from <em>halal</em> (to praise/boast), here with negative valence: the raving self-praise of the unstable person. The progression is important: the fool begins in mere folly (cognitive error) and ends in <em>ra'ah holelut</em> (wicked madness) — the escalation of unchecked foolish speech. The end-state is not merely foolish but morally corrupted and psychologically unmoored.</p>",
    "14": "<p><strong>vehassakal yarbeh devarim</strong>: 'The fool multiplies words.' <em>Yarbeh devarim</em> — the verbal excess of the fool is a consistent wisdom observation (Prov 10:19; Eccl 5:3). <em>Lo yeda ha'adam mah sheyihyeh</em>: 'a man does not know what will happen.' The epistemological limit is not the fool's alone but a universal condition — yet the fool speaks voluminously about the future as if he knows. <em>Va'asher yihyeh me'acharayv mi yaggid lo</em>: 'and who will tell him what will come after him?' The rhetorical question reinforces the point: the fool multiplies words about the unknowable. Qohelet consistently uses the <em>lo yeda</em> (does not know) formula to mark the limits that wisdom recognizes and folly ignores.</p>",
    "15": "<p><strong>amal hakesilim teyaggenenu</strong>: 'The labor of fools wearies him.' The referent is singular (<em>teyaggenenu</em>, wearies him) though the subject is plural — Qohelet often uses the collective. The classic sign of extreme disorientation: <em>asher lo yada lalekheth el-ir</em>: 'one who does not know how to go to the city.' In ancient Palestine, cities were visible landmarks for navigation — not knowing how to reach the city is the paradigm of radical lostness. The fool exhausts himself in labor (<em>amal</em>) and still cannot manage basic orientation. The proverb is not about literal geography but about the fool's profound practical incompetence despite great effort.</p>",
    "16": "<p><strong>oy lakh eretz shemalkeikh na'ar</strong>: 'Woe to you, land, whose king is a boy.' <em>Na'ar</em> (youth, boy) — not necessarily age but immaturity of character; the word covers both young age and immature judgment (cf. 1 Kgs 3:7 where Solomon calls himself <em>na'ar</em> at the start of his reign — not as a boast but as a confession of inadequacy). <em>Vesaraiikh baboqer yokhelu</em>: 'and your princes feast in the morning' — the morning feast signals that governing has been abandoned in favor of pleasure at the hour when officials should be conducting affairs of state.</p>",
    "17": "<p><strong>ashreikh eretz shemalkeikh ben-chorim</strong>: 'Blessed is the land whose king is a son of freemen.' <em>Ben-chorim</em> (son of free people, son of nobles) — <em>chorim</em> derives from the root suggesting whiteness or nobility; but Qohelet uses it for character-nobility rather than bloodline. The contrast with <em>na'ar</em> (verse 16) is between immaturity-regardless-of-lineage and mature-character-regardless-of-lineage. <em>Bishvul gevurah</em>: 'for strength/self-mastery' — the princes eat at the proper time for strength, not for drunkenness. The same word <em>gevurah</em> (might) that describes divine power is here the quality of the self-disciplined official who eats to serve rather than to indulge.</p>",
    "18": "<p><strong>beatslayim yimakh hamiqreh</strong>: 'Through great laziness the rafters sag.' <em>Atslayim</em> (double laziness, great sloth) — the intensified plural. <em>Miqreh</em> (rafter, roof-beam) — the structural support element. <em>Ushiflut yadayim yidlof habayit</em>: 'and through idle hands the house leaks.' The house neglected by idle hands leaks through its roof. Qohelet applies this as a political metaphor for the governing failures of vv.16-17: the land whose rulers are immature or self-indulgent is the house whose rafters sag — the structural decay of lazy governance is as predictable and visible as a leaking roof.</p>",
    "19": "<p><strong>lishtok laasim lechem</strong>: 'A feast is prepared for laughter.' <em>Lishtok</em> (for laughter, for merriment) — the purpose of the feast. <em>Vehayayin yesammach chayyim</em>: 'and wine gladdens life.' <em>Vehaakaseph ya'aneh et hakol</em>: 'but money answers everything.' The verse is possibly ironic — the rulers of verse 16 prepare feasts for pleasure and claim wine gladdens life, but money provides for everything. The final clause (<em>hakaseph ya'aneh et hakol</em>) may be their rationalization: since money solves problems, the extravagant feast is justified. Qohelet's dry observation neither endorses nor fully condemns — he notes the rulers' own self-justifying logic as another expression of the governing malfunction he has been describing.</p>",
    "20": "<p><strong>gam bemadakha al teqallel melek</strong>: 'Do not curse the king even in your intimate knowledge.' <em>Madakha</em> (your intimate thoughts, your knowledge/awareness) — the inner chamber of thought. <em>Uvechadrei mishkavkha al teqallel ashir</em>: 'even in the chambers of your bed do not curse the rich.' The rationale: <em>ki of hashamayim yolich et haqol</em>: 'for a bird of the heavens will carry the voice.' <em>Tzipporah</em> (bird) — the saying about bird-carried secrets may be a proverbial expression for information that spreads through informal channels. The practical wisdom: even private speech is not private. There is an economy of words even in thought and bedroom — the counsel to prudent speech extends to its most private forms.</p>"
  },
  "11": {
    "1": "<p><strong>shalach lachmekha al penei hamayim</strong>: 'Cast your bread upon the face of the waters.' <em>Lachem</em> (bread, food) — in the context of the wisdom tradition, the image may also evoke grain sent out in commerce (grain-ships on the Nile or Mediterranean). <em>Al penei hamayim</em> (upon the face of the waters) — the investment cast into the uncertain medium of trade or generosity, where outcomes are not controlled. <em>Ki berov hayamim timtzaenu</em>: 'for after many days you will find it again.' <em>Berov hayamim</em> (in the abundance of days, after many days) — the return is real but temporally deferred. The wisdom is about the willingness to release what one has into uncertain channels, trusting the return that cannot be predicted or controlled.</p>",
    "2": "<p><strong>ten cheleq leshivah vegam lishmonah</strong>: 'Give a portion to seven, even to eight.' The surplus-giving beyond calculation: seven is a round number suggesting fullness; <em>vegam lishmonah</em> (and even to eight) pushes past the complete number, indicating generosity that exceeds what would be strictly required. <em>Ki lo teda mah yihyeh ra'ah al ha'aretz</em>: 'for you do not know what calamity may come upon the land.' The rationale for surplus generosity is epistemic — future calamity is unknown, and having distributed generously creates the relational and social network that sustains people through calamity. Generosity as an investment strategy under uncertainty.</p>",
    "3": "<p><strong>im yimmal'u he'avim geshem al ha'aretz yariqu</strong>: 'If the clouds are full of rain, they pour it on the earth.' The cloud-rain example is of determined outcomes: filled clouds pour — there is no uncertainty. <em>Ve'im yipol etz badrom o batzafon</em>: 'and if a tree falls to the south or to the north.' <em>Bimqom sheyyipol haetz sham yihyu</em>: 'in the place where the tree falls, there it lies.' The fallen tree lies where it fell — past events are fixed. Together vv.3-4 frame the dilemma of action under uncertainty: some things are determined (clouds pour, trees stay where they fall), and the person who waits for perfect conditions (no wind, no clouds) will never sow or reap. Past fixity and future uncertainty together call for present action.</p>",
    "4": "<p><strong>shomer ruach lo yizra</strong>: 'Whoever watches the wind will not sow.' <em>Ruach</em> (wind, spirit) — the dual meaning will be activated in verse 5. Here it is wind: the farmer who watches wind conditions looking for the perfect windless day will never sow his seed. <em>Vero'eh be'avim lo yiqtzor</em>: 'and whoever watches the clouds will not reap.' The weather-watcher who waits for certainty before acting produces nothing. The proverb commends action in the face of imperfect conditions rather than the paralysis of perpetual uncertainty-management. The person who never acts until all risks are eliminated makes the worst decision by default.</p>",
    "5": "<p><strong>ka'asher einekha yode'a mah derech haruach</strong>: 'Just as you do not know the path of the wind.' <em>Ruach</em> here carries both meanings simultaneously — wind (the meteorological phenomenon) and spirit/breath (the animating principle). <em>Ke'atzamot bebeten hamele'ah</em>: 'like the bones in the womb of a pregnant woman' — the formation of the skeletal structure in utero. <em>Kakah lo teda et ma'aseh ha'elohim asher ya'aseh et hakol</em>: 'so you do not know the work of God who makes everything.' The two unknowable things — the path of the wind-spirit and the formation of bones in the womb — are both examples of God's creational work that proceeds beyond human observation. Qohelet uses this observation to motivate action despite ignorance rather than paralysis.</p>",
    "6": "<p><strong>bazzoqer zera et zar'ekha</strong>: 'In the morning sow your seed.' <em>Zera... zar'ekha</em> — the verb and noun from the same root for maximal emphasis on the act of sowing. <em>Velaerev al tanach yadekha</em>: 'and in the evening do not let your hand rest.' The double-shift work ethic: sow morning and evening without ceasing. <em>Ki einekha yode'a ei zeh yikshur</em>: 'for you do not know which will succeed.' The epistemic uncertainty (lo yeda) that would paralyze the weather-watcher instead motivates the double-sower — precisely because you don't know which planting will prosper, you maximize both and trust one or both to produce. The <em>o shneihem ke'echad tovim</em> (or whether both will be equally good) is the hoped-for outcome of comprehensive diligence.</p>",
    "7": "<p><strong>umetuq ha'or</strong>: 'Light is sweet.' <em>Metuq</em> (sweet) — sensory pleasure applied to sight. <em>Vetov la'einayim lir'ot et hashemesh</em>: 'and good for the eyes to see the sun.' This two-word observation (<em>umetuq ha'or</em>) opens the joy-section of 11:7-12:1 — the positive commendation of present delight before the aging and death section of chapter 12. The sweetness of light is not an argument for hedonism but a genuine acknowledgment of the goodness of created existence. Qohelet's recurring commendation of joy (<em>simcha</em>) is grounded in the goodness of the created world even within the context of its transience.</p>",
    "8": "<p><strong>ki im shanah harbe yichyeh ha'adam</strong>: 'If a person lives many years.' <em>Bekhullam yismach</em>: 'in all of them let him rejoice.' The comprehensive-joy instruction: joy through the full length of life, not reserved for certain seasons. <em>Veyizkor et yemei hachoshekh ki harbeh yihyu</em>: 'but let him remember the days of darkness, for they will be many.' <em>Yemei hachoshekh</em> (days of darkness) — approaching death, the long undifferentiated darkness before the chapter 12 imagery. <em>Kol sheba havel</em>: 'all that comes is vapor.' The joy-and-remember structure: joy is commended, but the memory of darkness prevents the joy from becoming blind cheerfulness. Both are real.</p>",
    "9": "<p><strong>simach bachur beyaldutekha</strong>: 'Rejoice, young man, in your youth.' <em>Beyaldutekha</em> (in your childhood/youth) — the unrecoverable time of youthful energy. <em>Vetov libekha bimei bechurotekha</em>: 'let your heart be good in the days of your prime.' <em>Bechurot</em> (prime of youth, vigor of youth) — the fullness of young strength. <em>Vehalekh bidarkhei libekha uvemara'ei einekha</em>: 'and walk in the ways of your heart and the sights of your eyes.' Qohelet endorses the full use of the young person's capacities — and then adds the crucial frame: <em>veda ki al kol eleh yeviaakha ha'elohim bamishpat</em>: 'and know that for all these things God will bring you into judgment.' The joy is real and commended; the accounting is also real and unavoidable.</p>",
    "10": "<p><strong>vehasir ka'as milibekha</strong>: 'Banish anxiety from your heart.' <em>Ka'as</em> (vexation, irritation, anxiety — the gnawing frustration Qohelet has observed throughout) — here commanded away. <em>Veha'aver ra'ah mibbesarekha</em>: 'and put away pain from your body.' <em>Ki heyaldut vehashachachar havel</em>: 'for childhood and the prime of youth are vapor.' <em>Shachachar</em> (dawn, the first light) — a rare form; the youth-dawn connection suggests the fleeting first light of the day as the image for youth: beautiful, brief, already passing as it arrives. The verse closes the youth-section with the <em>hevel</em> verdict on youth itself — the vapor-breath that Qohelet has used throughout finally lands on the most energetic stage of human life.</p>"
  },
  "12": {
    "1": "<p><strong>uzekhor et borekha bimei bechurotekha</strong>: 'Remember your Creator in the days of your youth.' <em>Borekha</em> (your Creator) — plural of majesty from <em>bara</em> (to create). The command to <em>zekor</em> (remember) is the covenant call that runs through Deuteronomy — remembering is not merely cognitive recall but the active orientation of life toward what one knows. The <em>bimei bechurotekha</em> (in the days of your prime/youth) connects directly to 11:9's commendation of youth, adding the frame: youth is precisely the season for this orientation, before the deterioration described in the extended allegory that follows. <em>Ad asher lo yavo'u yemei hara'ah</em>: 'before the days of trouble come' — the aging and dying that chapter 12 elaborates.</p>",
    "2": "<p><strong>ad asher lo techeshah hashemesh veha'or</strong>: 'Before the sun and the light grow dark.' The extended allegory of aging begins (vv.2-7), using cosmic and architectural imagery for the body's decline. The darkening of sun, light, moon, and stars has been interpreted as either a description of the old person's failing senses or as cosmic dissolution imagery. <em>Veshabu he'avim achar haggeshem</em>: 'and the clouds return after the rain' — unlike in summer when rain brings clearing, in old age the clouds return repeatedly, suggesting the relentless succession of ailments in old age where one illness follows another without full recovery in between.</p>",
    "3": "<p><strong>beyom sheyir'azu shomrei habayit</strong>: 'In the day when the keepers of the house tremble.' The allegorical interpretation has a long tradition: <em>shomrei habayit</em> (keepers of the house) = arms/hands that tremble with age. <em>Ve'hit'avtu anshei hachayil</em>: 'and the men of valor become bent' = the legs that once bore the body's strength now bow. <em>Uvatellu hatochnot ki me'etu</em>: 'and the grinders cease because they are few' = the teeth. <em>Vechashechu haro'ot ba'arubbot</em>: 'and those who look through the windows grow dim' = the eyes. The body-house allegory transforms the physical decline of aging into a scene of architectural decay — simultaneously more dignified and more poignant than clinical description.</p>",
    "4": "<p><strong>vesuggeru delatayim bashuk</strong>: 'When the street doors are shut' — possibly the mouth closed from lack of teeth (continuing the body-allegory), or the social withdrawal of old age. <em>Bishfal qol hatachanah</em>: 'when the sound of grinding is low' — the grinding mills (the teeth) silent. <em>Veyaqum leqol hatzippur</em>: 'when one rises at the sound of a bird' — the light sleep of the elderly who wake at any sound. <em>Veyishshachu kol benot hashir</em>: 'and all the daughters of song are brought low' — the voice and hearing fail; the singing and hearing of music that characterized the earlier seasons of life (11:9: the feast and joy) are diminished.</p>",
    "5": "<p><strong>gam migavoha yira'u</strong>: 'And they will be afraid of heights.' <em>Vechatchtim baderekh</em>: 'and dread is on the path' — the confined world of the aged person who fears heights and dread every journey. <em>Veyafetz hashaqed</em>: 'when the almond tree blossoms' — the white blossoms on the bare branches of the almond tree in late winter, the first tree to blossom, are the image for white hair on an old head. <em>Veyistabbal hechagav</em>: 'when the locust drags itself along' — the labored movement of the aged. <em>Vetafer ha'aviyyonah</em>: 'and the caperberry fails' — possibly an aphrodisiac plant whose failure signals the end of sexual vitality. <em>Ki holekh ha'adam el beit olamo</em>: 'for man goes to his eternal home' — <em>beit olamo</em> (house of his eternity/the grave) — the destination toward which all the failing capacities converge.</p>",
    "6": "<p><strong>ad asher lo yeratteq chevvel hakkesef</strong>: 'Before the silver cord is severed.' <em>Chevvel hakesef</em> (cord of silver) — the silver cord that breaks; in the body-allegory, possibly the spinal cord or the breath/life-thread. <em>Vetaruts gullat hazahav</em>: 'and the golden bowl is shattered' — the bowl of gold that cracks; the brain, or the lamp that illuminates. <em>Veyishaver kad al hamayyin</em>: 'and the pitcher is broken at the spring' — the lungs or heart at the spring of breath. <em>Venarots hagalal el habor</em>: 'and the wheel breaks at the cistern' — the pulley at the water-well, the heart or the circulatory system. The four broken-things images form a unified picture of the body's cessation — the cord, the bowl, the pitcher, the wheel — each representing a vital system that finally fails.</p>",
    "7": "<p><strong>veyashov ha'afar al ha'aretz kashehayyah</strong>: 'The dust returns to the earth as it was.' The direct citation of Gen 3:19: <em>ki afar atah ve'el afar tashuv</em> (for you are dust and to dust you shall return). Qohelet's entire preceding allegory has been elaborating this single verse from Genesis. <em>Veharuach tashuv el ha'elohim asher netanah</em>: 'and the spirit returns to God who gave it.' The body returns to its material origin; the spirit (<em>ruach</em>) returns to its divine source. This is not a detailed theology of the afterlife but an acknowledgment that the life-breath is God's gift from beginning to end, returned to the Giver at death. The <em>netanah</em> (who gave it) frames the entire life between gift and return.</p>",
    "8": "<p><strong>havel havalim amar haqohelet hakol havel</strong>: 'Vapor of vapors, says the Teacher — all is vapor.' The book closes (or near-closes) with the opening refrain of 1:2 — the <em>inclusio</em> that frames the entire work. Between the opening and closing <em>havel havalim</em>, Qohelet has observed kings and fools, wisdom and madness, labor and rest, feasts and funerals, youth and old age, the living and the dead. The final <em>havel</em> is not nihilistic despair but the considered conclusion of comprehensive observation: the transience of all things is the consistent finding of careful attention to reality.</p>",
    "9": "<p><strong>veyoter shehayyah qohelet chakham</strong>: 'Beyond this, the Teacher was wise.' The epilogue (vv.9-14) shifts from first-person discourse to a third-person description of Qohelet's work. <em>Od limmad da'at et ha'am</em>: 'he also taught knowledge to the people.' <em>Ve'izen vichiqer tiqen meshalim harbeh</strong>: 'he listened, investigated, and arranged many proverbs.' <em>Izen</em> (listened, weighed carefully) — from <em>ozen</em> (ear); the process of careful reception. <em>Chiqer</em> (searched, investigated) — from <em>chaqar</em>, to probe. <em>Tiqen</em> (arranged, set in order) — the final editorial work of giving structure to what was received and investigated. The three-stage wisdom process: receptive listening, active investigation, careful arrangement.</p>",
    "10": "<p><strong>biqqesh qohelet limtzo divrei cheifetz</strong>: 'The Teacher sought to find pleasing words.' <em>Divrei cheifetz</em> (words of delight/pleasure) — not superficially entertaining but deeply satisfying words. <em>Vekatuv yosher divrei emet</em>: 'and written uprightly — words of truth.' <em>Yosher</em> (uprightness, honesty) and <em>emet</em> (truth, reliability) — the two standards that governed the Teacher's writing. The double commitment — to pleasing form and honest content — is the ideal of wisdom literature: the words should be both artistically satisfying and truthfully accurate. The form serves the content; the content requires honest investigation; both together are the <em>cheifetz</em> (delight) the Teacher sought.</p>",
    "11": "<p><strong>divrei chakhamim kadarbenot</strong>: 'The words of the wise are like goads.' <em>Darbenot</em> (goads) — the pointed stick that moves animals; wisdom-words that prod the mind toward action. <em>Uchemasmerot netu'im ba'alei asufot</em>: 'and like firmly driven nails are the collected sayings.' <em>Ba'alei asufot</em> (masters of collections, members of collections) — the assembled body of wisdom sayings. <em>Nittenu mere'eh echad</em>: 'given by one Shepherd.' <em>Ro'eh echad</em> (one Shepherd) — the single source behind the multiple wisdom traditions. Qohelet here draws together all the wisdom teaching under the image of the one Shepherd — the divine source from whom all wisdom ultimately derives, regardless of its human compilers.</p>",
    "12": "<p><strong>veyoter meheimah beni hizzaher</strong>: 'Beyond these, my son, be warned.' The <em>beni</em> (my son) address echoes the father-son frame of Proverbs 1-9 — wisdom tradition addressing the next generation. <em>Asot sefarim harbeh ein qetz</em>: 'making many books has no end.' The epistemological limit of the written corpus: books multiply without limit. <em>Velagg limmud harbe yegi'at basar</em>: 'and much study is weariness of the flesh.' The study that goes beyond the collected wisdom into endless book-making is identified as bodily exhaustion rather than the profitable labor (<em>yitron amal</em>) Qohelet has sought throughout. The warning is not against learning but against the mistaking of book-proliferation for wisdom.</p>",
    "13": "<p><strong>sof davar hakol nishma</strong>: 'The conclusion of the matter — all has been heard.' <em>Sof davar</em> (the end of the matter, the conclusion) — the logical conclusion drawn from everything Qohelet has observed and said. <em>Et ha'elohim yera ve'et mitzvotav shemor ki zeh kol ha'adam</em>: 'Fear God and keep his commandments — for this is the whole of man.' <em>Kol ha'adam</em> (the whole of man, the entirety of man) — not merely the duty but the definition: this is what the human being finally is, in sum. The <em>yirat elohim</em> (fear of God) that Proverbs 1:7 places at the beginning as the start of wisdom, Qohelet places at the end as its conclusion — the beginning and end of the wisdom tradition converge on the same foundation.</p>",
    "14": "<p><strong>ki et kol ma'aseh yavi ha'elohim bamishpat</strong>: 'For God will bring every deed into judgment.' <em>Al kol ne'elam</em>: 'concerning every hidden thing' — <em>ne'elam</em> (hidden, concealed) from <em>alam</em> (to be hidden/silent). The judgment is comprehensive: every action, <em>im tov ve'im ra</em> (whether good or whether evil). Qohelet's conclusion does not rest on epistemological humility alone (we don't know what will happen) but on the theological certainty that God's judgment will ultimately adjudicate what human observation cannot reach. The hidden things that escape human reckoning do not escape the divine accounting. This final verse transforms the entire book's observations about the limits of human knowledge into an argument for moral seriousness under divine sovereignty.</p>"
  }
}

def main():
    e = load_comm('mkt-original', 'ecclesiastes')
    merge_comm(e, DATA)
    save_comm('mkt-original', 'ecclesiastes', e)
    count = sum(len(v) for v in DATA.values())
    print(f'ecclesiastes mkt-original: wrote {count} verses across ch 10-12')

if __name__ == '__main__':
    main()
